30	/// Build the spec fixture: embedding + causal attention block +
31	/// MLP block + final projection head. Contains every parameter
32	/// family needed to exercise the four family strings.
33	fn build_fixture(env: &mut Environment) {
34	    let src = "base = chain(embed(8, 4, 0),\
35	                             residual(chain(rms_norm(4), causal_attention(4, 1, 1))),\
36	                             residual(chain(rms_norm(4),\
37	                                            linear(4, 16, 2),\
38	                                            relu_layer(),\
39	                                            linear(16, 4, 3))),\
40	                             rms_norm(4),\
41	                             linear(4, 8, 4))";
42	    run(env, src);
43	    run(env, "copy = clone_model(base)");
44	}
45	
46	/// Snapshot the tensor values for a model's params, keyed by name.
47	fn snapshot(env: &Environment, model_ident: &str) -> HashMap<String, Vec<f64>> {
48	    let names = model_params(env, model_ident).unwrap();
49	    let mut out = HashMap::new();
50	    for n in names {
51	        let v = env.get(&n).unwrap().data().to_vec();
52	        out.insert(n, v);
53	    }
54	    out
55	}
