57	/// Return the subset of param names whose values differ between
58	/// `before` and `after` (both assumed to be same-keyed maps).
59	fn changed_params(
60	    before: &HashMap<String, Vec<f64>>,
61	    after: &HashMap<String, Vec<f64>>,
62	) -> HashSet<String> {
63	    let mut out = HashSet::new();
64	    for (name, old) in before {
65	        if old != after.get(name).unwrap() {
66	            out.insert(name.clone());
67	        }
68	    }
69	    out
70	}
