72	/// Largest absolute delta between two same-shape tensor data vecs.
73	fn max_abs_delta(before: &[f64], after: &[f64]) -> f64 {
74	    before
75	        .iter()
76	        .zip(after.iter())
77	        .map(|(a, b)| (a - b).abs())
78	        .fold(0.0_f64, f64::max)
79	}
