98	        changed.len(),
99	        copy_before.len(),
100	        "all_layers must perturb every parameter"
101	    );
102	
103	    // Gaussian noise * sigma stays inside a practical bound. We use
104	    // 10*sigma rather than 6*sigma because `randn` goes through
105	    // Box-Muller on a 53-bit uniform; the theoretical max magnitude
106	    // is ~sqrt(-2 * ln(2^-53)) = sqrt(2 * 37 * ln 2) ~= 8.6, so 10x
107	    // is a safe practical ceiling while still catching any serious
108	    // scaling bug (an outright `sigma` mis-application would blow
109	    // past this easily).
110	    let ten_sigma = 10.0 * 0.02;
111	    for (name, before) in &copy_before {
112	        let after = copy_after.get(name).unwrap();
113	        let d = max_abs_delta(before, after);
114	        assert!(
115	            d <= ten_sigma,
116	            "delta on {name} should stay within 10*sigma, got {d}"
117	        );
118	    }
119	}
