1	//! Saga 20 step 002: `perturb_params(m, family, sigma, seed)`.
2	//!
3	//! Walks a model's parameter set, filters by family, and adds
4	//! `sigma * randn(seed, shape)` to each matching parameter in
5	//! place. The core of the Neural Thickets workflow.
6	//!
7	//! See `contracts/eval-contract/perturb-params.md` for the
8	//! behavioural contract.
9	
10	use std::collections::HashSet;
11	
12	use mlpl_array::{DenseArray, Shape};
13	use mlpl_parser::Expr;
14	
15	use crate::env::Environment;
16	use crate::error::EvalError;
17	use crate::model::ModelSpec;
18	
19	const FAMILIES: &[&str] = &["all_layers", "attention_only", "mlp_only", "embed_and_head"];
20	
21	/// `perturb_params(m, family, sigma, seed)` -- apply family-targeted
22	/// Gaussian noise to a model's parameters, in place. Returns a
23	/// scalar zero so the call can sit in statement or expression
24	/// position, mirroring `to_device`'s unit-return convention.
25	pub(crate) fn eval_perturb_params(
26	    args: &[Expr],
27	    env: &mut Environment,
28	) -> Result<DenseArray, EvalError> {
29	    if args.len() != 4 {
30	        return Err(EvalError::BadArity {
31	            func: "perturb_params".into(),
32	            expected: 4,
33	            got: args.len(),
34	        });
35	    }
36	    let model_name = match &args[0] {
37	        Expr::Ident(n, _) => n.clone(),
38	        _ => {
39	            return Err(EvalError::Unsupported(
40	                "perturb_params: first argument must be a model identifier".into(),
41	            ));
42	        }
43	    };
44	    let spec = env.get_model(&model_name).cloned().ok_or_else(|| {
45	        EvalError::Unsupported(format!("perturb_params: '{model_name}' is not a model"))
46	    })?;
47	    let family = match &args[1] {
48	        Expr::StrLit(s, _) => s.clone(),
49	        _ => {
50	            return Err(EvalError::Unsupported(
51	                "perturb_params: family (second argument) must be a string literal".into(),
52	            ));
53	        }
54	    };
55	    if !FAMILIES.contains(&family.as_str()) {
56	        return Err(EvalError::Unsupported(format!(
57	            "perturb_params: unknown family '{family}' (expected one of {})",
58	            FAMILIES.join(", ")
59	        )));
60	    }
61	    let sigma = scalar_f64(&args[2], env)?;
62	    let seed = scalar_f64(&args[3], env)?;
63	
64	    let head = head_param_names(&spec);
65	    let affected = filter_family(&spec.params(), &family, &head);
66	    for (i, name) in affected.iter().enumerate() {
67	        perturb_one(env, name, sigma, seed + i as f64)?;
68	    }
69	    Ok(DenseArray::from_scalar(0.0))
70	}
71	
72	/// Parameter names owned by the "final projection head": the last
73	/// top-level `Linear` child of the outermost `Chain`, or the model
74	/// itself if it is a bare `Linear`. Returns an empty set when the
75	/// outermost node is anything else (e.g. a `Residual` wrapper), in
76	/// which case no param is treated as the head.
77	fn head_param_names(spec: &ModelSpec) -> HashSet<String> {
78	    let head_linear = match spec {
79	        ModelSpec::Linear { .. } => Some(spec),
80	        ModelSpec::Chain(children) => children
81	            .iter()
82	            .rev()
83	            .find(|c| matches!(c, ModelSpec::Linear { .. })),
84	        _ => None,
85	    };
86	    match head_linear {
87	        Some(ModelSpec::Linear { w, b }) => [w.clone(), b.clone()].into_iter().collect(),
88	        _ => HashSet::new(),
89	    }
90	}
91	
92	/// Filter an ordered list of param names by family membership. The
93	/// head set is consulted so `mlp_only` can exclude the projection
94	/// head and `embed_and_head` can include it.
95	fn filter_family(all: &[String], family: &str, head: &HashSet<String>) -> Vec<String> {
96	    all.iter()
97	        .filter(|name| match family {
98	            "all_layers" => true,
99	            "attention_only" => name.starts_with("__attn_"),
100	            "mlp_only" => name.starts_with("__linear_") && !head.contains(*name),
101	            "embed_and_head" => name.starts_with("__embed_") || head.contains(*name),
102	            _ => false,
103	        })
104	        .cloned()
105	        .collect()
106	}
107	
108	/// Apply `sigma * randn(seed, shape(param))` to the named parameter
109	/// in place. Preserves `env.params` membership and device tag
110	/// because we only touch the underlying value via `env.set`.
111	fn perturb_one(env: &mut Environment, name: &str, sigma: f64, seed: f64) -> Result<(), EvalError> {
112	    let old = env
113	        .get(name)
114	        .cloned()
115	        .ok_or_else(|| EvalError::UndefinedVariable(name.into()))?;
116	    let shape_dims: Vec<f64> = old.shape().dims().iter().map(|&d| d as f64).collect();
117	    let shape_arr = DenseArray::new(Shape::new(vec![shape_dims.len()]), shape_dims)?;
118	    let noise =
119	        mlpl_runtime::call_builtin("randn", vec![DenseArray::from_scalar(seed), shape_arr])?;
120	    let new_data: Vec<f64> = old
121	        .data()
122	        .iter()
123	        .zip(noise.data().iter())
124	        .map(|(o, n)| o + sigma * n)
125	        .collect();
126	    let new_tensor = DenseArray::new(old.shape().clone(), new_data)?;
127	    env.set(name.to_string(), new_tensor);
128	    Ok(())
129	}
